function loadHtml2Canvas() {
  return new Promise((resolve, reject) => {
    if (window.html2canvas) { resolve(window.html2canvas); return; }
    const script = document.createElement("script");
    script.src = "https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js";
    script.onload = () => resolve(window.html2canvas);
    script.onerror = reject;
    document.head.appendChild(script);
  });
}

export default function DashboardScreen({ data, sessionId, colorSchema, onReset }) {
  const { dashboard_title, charts, insights, summary, total_kpis_generated } = data;
  const exportRef = useRef(null);
  const [exporting, setExporting]   = useState(false);
  const [exportType, setExportType] = useState("");
  const [showMenu, setShowMenu]     = useState(false);

  const voiceContext = charts.map((c) => ({
    kpi: c.kpi, chart_type: c.chart_type, data: c.data.slice(0, 20),
  }));

  // ── PNG export ────────────────────────────────────────────────────────────
  const exportPNG = async () => {
    setShowMenu(false); setExporting(true); setExportType("png");
    try {
      const h2c = await loadHtml2Canvas();
      const el  = exportRef.current;

      // Temporarily make scrollable areas full-height for capture
      const mainCol = el.closest("[data-maincol]");
      let oldOverflow = "";
      if (mainCol) { oldOverflow = mainCol.style.overflow; mainCol.style.overflow = "visible"; }

      const canvas = await h2c(el, {
        backgroundColor: "#07090f",
        scale: 2,
        useCORS: true,
        allowTaint: true,
        logging: false,
        scrollX: 0,
        scrollY: -window.scrollY,
        windowWidth: el.scrollWidth,
        windowHeight: el.scrollHeight,
      });

      if (mainCol) mainCol.style.overflow = oldOverflow;

      const link = document.createElement("a");
      link.download = `${dashboard_title.replace(/\s+/g, "_")}.png`;
      link.href = canvas.toDataURL("image/png", 1.0);
      link.click();
    } catch (err) {
      console.error(err);
      alert("PNG export failed: " + err.message);
    } finally { setExporting(false); setExportType(""); }
  };

  // ── PDF export ────────────────────────────────────────────────────────────
  const exportPDF = async () => {
    setShowMenu(false); setExporting(true); setExportType("pdf");
    try {
      const h2c    = await loadHtml2Canvas();
      const el     = exportRef.current;

      const canvas = await h2c(el, {
        backgroundColor: "#07090f",
        scale: 1.8,
        useCORS: true,
        allowTaint: true,
        logging: false,
        scrollX: 0,
        scrollY: -window.scrollY,
        windowWidth: el.scrollWidth,
        windowHeight: el.scrollHeight,
      });

      const imgData  = canvas.toDataURL("image/png", 0.95);
      const imgW     = canvas.width;
      const imgH     = canvas.height;
      const date     = new Date().toLocaleDateString("en-US", { year:"numeric", month:"long", day:"numeric" });

      const pw = window.open("", "_blank");
      if (!pw) { alert("Please allow popups for this site to export PDF."); setExporting(false); return; }

      pw.document.write(`<!DOCTYPE html><html><head>
        <title>${dashboard_title}</title>
        <style>
          *{margin:0;padding:0;box-sizing:border-box;}
          body{background:#07090f;font-family:sans-serif;}
          .hdr{background:#0d1018;padding:18px 32px;display:flex;justify-content:space-between;align-items:center;border-bottom:1px solid #1e2640;}
          .hdr-left h1{color:#e2e8f8;font-size:20px;font-weight:800;margin-bottom:4px;}
          .hdr-left p{color:#7b849e;font-size:12px;}
          .hdr-right{text-align:right;color:#7b849e;font-size:12px;line-height:1.7;}
          .hdr-right span{color:#5b8def;font-weight:700;}
          img{display:block;width:100%;height:auto;}
          @media print{body{-webkit-print-color-adjust:exact;print-color-adjust:exact;}@page{margin:0;size:A4 landscape;}}
        </style></head><body>
        <div class="hdr">
          <div class="hdr-left">
            <h1>📊 ${dashboard_title}</h1>
            <p>Generated by Talking BI · ${date}</p>
          </div>
          <div class="hdr-right">
            <div><span>${total_kpis_generated}</span> Charts Generated</div>
          </div>
        </div>
        <img src="${imgData}" />
        <script>window.onload=function(){setTimeout(function(){window.print();},600);};<\/script>
      </body></html>`);
      pw.document.close();
    } catch (err) {
      console.error(err);
      alert("PDF export failed: " + err.message);
    } finally { setExporting(false); setExportType(""); }
  };

  return (
    <div style={S.screen}>

      {/* ── Topbar ──────────────────────────────────────────────────────── */}
      <div style={S.topbar}>
        <div style={S.topLeft}>
          <div style={S.logoWrap}>
            <svg width="16" height="16" viewBox="0 0 28 28" fill="none">
              <circle cx="14" cy="14" r="12.5" stroke="#5b8def" strokeWidth="1.5"/>
              <path d="M8 19 L12 9 L16 15 L20 7" stroke="#5b8def" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
              <circle cx="20" cy="7" r="2" fill="#8b5cf6"/>
            </svg>
          </div>
          <h1 style={S.title}>{dashboard_title}</h1>
          <div style={S.chartsBadge}>{total_kpis_generated} charts</div>
        </div>

        <div style={S.actions}>
          {/* Export dropdown */}
          <div style={{ position:"relative" }}>
            <button
              style={{ ...S.exportBtn, ...(exporting ? S.exportBtnOff : {}) }}
              onClick={() => !exporting && setShowMenu(v => !v)}
              disabled={exporting}
            >
              {exporting ? (
                <><span style={S.spinner}/>{exportType === "pdf" ? "Saving PDF…" : "Saving PNG…"}</>
              ) : (
                <>
                  <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
                    <path d="M7 1v8M4.5 6.5l2.5 2.5 2.5-2.5M2 10.5v1.5a1 1 0 001 1h8a1 1 0 001-1v-1.5" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round" strokeLinejoin="round"/>
                  </svg>
                  Export
                  <svg width="10" height="10" viewBox="0 0 10 10" fill="none">
                    <path d="M2 3.5l3 3 3-3" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/>
                  </svg>
                </>
              )}
            </button>

            {showMenu && (
              <div style={S.menu}>
                <button style={S.menuItem} onClick={exportPNG}>
                  <div style={S.menuIcon}>
                    <svg width="15" height="15" viewBox="0 0 15 15" fill="none">
                      <rect x="1" y="1" width="13" height="13" rx="2" stroke="#5b8def" strokeWidth="1.2"/>
                      <circle cx="5" cy="5.5" r="1.3" fill="#5b8def"/>
                      <path d="M1 10.5l3.5-3.5 2.5 2.5 2-2 4 4" stroke="#5b8def" strokeWidth="1.2" strokeLinecap="round" strokeLinejoin="round"/>
                    </svg>
                  </div>
                  <div>
                    <div style={S.menuTitle}>Save as PNG</div>
                    <div style={S.menuSub}>High-res image (2×)</div>
                  </div>
                </button>
                <div style={S.menuSep}/>
                <button style={S.menuItem} onClick={exportPDF}>
                  <div style={{ ...S.menuIcon, background:"rgba(245,158,11,0.1)", borderColor:"rgba(245,158,11,0.2)" }}>
                    <svg width="15" height="15" viewBox="0 0 15 15" fill="none">
                      <rect x="2" y="1" width="9" height="13" rx="1.5" stroke="#f59e0b" strokeWidth="1.2"/>
                      <path d="M4.5 4.5h5M4.5 7h5M4.5 9.5h3" stroke="#f59e0b" strokeWidth="1.2" strokeLinecap="round"/>
                      <path d="M9 1v4h4" stroke="#f59e0b" strokeWidth="1.2" strokeLinecap="round"/>
                    </svg>
                  </div>
                  <div>
                    <div style={{ ...S.menuTitle, color:"#f59e0b" }}>Save as PDF</div>
                    <div style={S.menuSub}>Print-ready landscape</div>
                  </div>
                </button>
              </div>
            )}
          </div>

          <button style={S.newBtn} onClick={onReset}>
            <svg width="13" height="13" viewBox="0 0 13 13" fill="none">
              <path d="M2 6.5a4.5 4.5 0 014.5-4.5 4.5 4.5 0 014.4 3.6M11 2v3.5H7.5" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/>
            </svg>
            New
          </button>
        </div>
      </div>

      {/* ── Body ────────────────────────────────────────────────────────── */}
      <div style={S.body}>

        {/* Charts area */}
        <div style={S.mainCol} data-maincol="true">
          <div ref={exportRef} style={S.exportArea}>
            <div style={S.grid}>
              {charts.map((chart, i) => (
                <ChartCard key={chart.kpi} chart={chart} colorSchema={colorSchema} index={i} />
              ))}
            </div>
          </div>
        </div>

        {/* Sidebar — voice + insights only (no duplicate summary) */}
        <div style={S.sidebar}>
          <VoicePanel sessionId={sessionId} dashboardContext={voiceContext} />
          <InsightPanel insights={insights} summary={summary} />
        </div>
      </div>

      {/* Overlay to close menu */}
      {showMenu && <div style={S.overlay} onClick={() => setShowMenu(false)} />}
    </div>
  );
}

const S = {
  screen:  { minHeight:"100vh", display:"flex", flexDirection:"column" },
  topbar:  { padding:"13px 24px", borderBottom:"1px solid var(--border)", display:"flex", alignItems:"center", justifyContent:"space-between", background:"rgba(7,9,15,0.94)", backdropFilter:"blur(16px)", position:"sticky", top:0, zIndex:30 },
  topLeft: { display:"flex", alignItems:"center", gap:12 },
  logoWrap:{ width:32, height:32, background:"rgba(91,141,239,0.1)", border:"1px solid rgba(91,141,239,0.18)", borderRadius:9, display:"flex", alignItems:"center", justifyContent:"center" },
  title:   { fontSize:17, fontWeight:800, color:"#fff", letterSpacing:"-0.3px" },
  chartsBadge:{ padding:"3px 10px", background:"rgba(91,141,239,0.1)", border:"1px solid rgba(91,141,239,0.2)", borderRadius:20, color:"var(--accent)", fontSize:11, fontWeight:700 },
  actions: { display:"flex", alignItems:"center", gap:10 },

  // Export button
  exportBtn: { display:"flex", alignItems:"center", gap:7, padding:"8px 16px", background:"rgba(91,141,239,0.1)", border:"1px solid rgba(91,141,239,0.25)", borderRadius:"var(--radius)", color:"var(--accent)", fontSize:13, fontWeight:600, cursor:"pointer", fontFamily:"'DM Sans',sans-serif" },
  exportBtnOff: { opacity:0.5, cursor:"not-allowed" },
  spinner: { width:13, height:13, border:"2px solid rgba(91,141,239,0.3)", borderTopColor:"var(--accent)", borderRadius:"50%", animation:"spin 0.7s linear infinite", display:"inline-block" },

  // Dropdown
  menu:     { position:"absolute", top:"calc(100% + 8px)", right:0, background:"var(--bg2)", border:"1px solid var(--border2)", borderRadius:"var(--radius-lg)", padding:6, minWidth:220, boxShadow:"0 20px 60px rgba(0,0,0,0.6)", zIndex:100, animation:"slideDown 0.15s ease" },
  menuItem: { display:"flex", alignItems:"center", gap:12, width:"100%", padding:"10px 12px", background:"none", border:"none", borderRadius:9, cursor:"pointer", textAlign:"left" },
  menuIcon: { width:34, height:34, background:"rgba(91,141,239,0.08)", border:"1px solid rgba(91,141,239,0.15)", borderRadius:8, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 },
  menuTitle:{ fontSize:13, fontWeight:600, color:"var(--accent)", marginBottom:2 },
  menuSub:  { fontSize:11, color:"var(--text3)" },
  menuSep:  { height:1, background:"var(--border)", margin:"4px 0" },

  newBtn: { display:"flex", alignItems:"center", gap:6, padding:"8px 14px", background:"var(--bg3)", border:"1px solid var(--border2)", borderRadius:"var(--radius)", color:"var(--text2)", fontSize:13, cursor:"pointer" },
  overlay:{ position:"fixed", inset:0, zIndex:20 },

  body:    { flex:1, display:"flex", overflow:"hidden" },
  mainCol: { flex:1, overflowY:"auto", padding:24 },
  exportArea: { background:"var(--bg)", borderRadius:"var(--radius-lg)", padding:4 },
  grid:    { display:"grid", gridTemplateColumns:"repeat(auto-fill, minmax(420px, 1fr))", gap:18 },

  sidebar: { width:370, borderLeft:"1px solid var(--border)", overflowY:"auto", padding:18, display:"flex", flexDirection:"column", gap:18, background:"var(--bg2)" },
};
